import React, { useState, useEffect } from 'react';
import { Routes, Route, Link, useNavigate } from 'react-router-dom';
import AddContent from './pages/AddContent';
import LoginPage from './pages/LoginPage';
import PostPage from './pages/PostPage';
import './App.css';
import 'react-quill/dist/quill.snow.css';

const BASE_URL = process.env.REACT_APP_API_URL || 'http://localhost:4000';

function App() {
  const [posts, setPosts] = useState([]);
  const [editingPostIndex, setEditingPostIndex] = useState(null);
  const [isAdmin, setIsAdmin] = useState(false);
  const navigate = useNavigate();

  // Load posts from backend
  useEffect(() => {
    fetch(`${BASE_URL}/posts`)
      .then((res) => res.json())
      .then((data) => setPosts(data))
      .catch((err) => console.error('Error loading posts:', err));
  }, []);

  const handleDeletePost = (index) => {
    fetch(`${BASE_URL}/posts/${index}`, {
      method: 'DELETE',
    })
      .then(() => {
        const updated = [...posts];
        updated.splice(index, 1);
        setPosts(updated);
      })
      .catch((err) => console.error('Failed to delete post:', err));
  };

  const handleEditPost = (index) => {
    const postToEdit = { ...posts[index], index };
    setEditingPostIndex(index);
    navigate('/add-content', { state: postToEdit });
  };

  const handleAddPost = (newPost) => {
    const today = new Date();
    const dateStr = today.toLocaleDateString('en-GB', {
      day: 'numeric',
      month: 'long',
      year: 'numeric',
    });

    newPost.date = dateStr;

    fetch(`${BASE_URL}/posts`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify(newPost),
    })
      .then(() => {
        setPosts((prev) => [newPost, ...prev]);
        setEditingPostIndex(null);
      })
      .catch((err) => console.error('Failed to add post:', err));
  };

  const handleLoginSuccess = () => {
    setIsAdmin(true);
    navigate('/');
  };

  return (
    <div className="app-container">
      <header className="header">
        {isAdmin ? (
          <Link to="/add-content">
            <button className="add-button">+ Add New Post</button>
          </Link>
        ) : (
          <Link to="/login">
            <button className="add-button">Login</button>
          </Link>
        )}

        <Link to="/" style={{ textDecoration: 'none' }}>
          <h1 className="title">Sofia’s Daily Blog 🌺</h1>
        </Link>
      </header>

      <Routes>
        <Route
          path="/"
          element={
            <main className="main">
              {posts.length === 0 ? (
                <p>No posts yet.</p>
              ) : (
                posts.map((post, idx) => (
                  <div
                    key={idx}
                    style={{
                      background: 'white',
                      padding: '1rem',
                      margin: '1rem 0',
                      borderRadius: '8px',
                      position: 'relative',
                    }}
                  >
                    {isAdmin && (
                      <div style={{ position: 'absolute', top: '10px', right: '10px' }}>
                        <details style={{ cursor: 'pointer' }}>
                          <summary style={{ fontSize: '1.2rem' }}>⋮</summary>
                          <div
                            style={{
                              position: 'absolute',
                              right: '0',
                              top: '20px',
                              background: '#fff',
                              border: '1px solid #ccc',
                              borderRadius: '6px',
                              boxShadow: '0 4px 8px rgba(0,0,0,0.1)',
                              zIndex: 1,
                            }}
                          >
                            <button
                              onClick={() => handleEditPost(idx)}
                              style={{
                                padding: '0.5rem 1rem',
                                width: '100%',
                                border: 'none',
                                background: 'white',
                                textAlign: 'left',
                                cursor: 'pointer',
                              }}
                            >
                              Edit
                            </button>
                            <button
                              onClick={() => handleDeletePost(idx)}
                              style={{
                                padding: '0.5rem 1rem',
                                width: '100%',
                                border: 'none',
                                background: 'white',
                                textAlign: 'left',
                                color: 'red',
                                cursor: 'pointer',
                              }}
                            >
                              Delete
                            </button>
                          </div>
                        </details>
                      </div>
                    )}

                    <Link to={`/post/${idx}`} style={{ textDecoration: 'none', color: 'black' }}>
                      <h2>{post.title}</h2>
                      {post.date && (
                        <p style={{ fontStyle: 'italic', color: 'gray', marginTop: '-0.5rem' }}>
                          Posted on {post.date}
                        </p>
                      )}
                      {post.previewImage && (
                        <img
                          src={post.previewImage}
                          alt="Preview"
                          style={{
                            width: '100%',
                            maxHeight: '200px',
                            objectFit: 'cover',
                            borderRadius: '8px',
                          }}
                        />
                      )}
                      {post.summary && <p>{post.summary}</p>}
                    </Link>
                  </div>
                ))
              )}
            </main>
          }
        />
        <Route path="/login" element={<LoginPage onLoginSuccess={handleLoginSuccess} />} />
        {isAdmin && <Route path="/add-content" element={<AddContent onAdd={handleAddPost} />} />}
        <Route path="/post/:id" element={<PostPage posts={posts} />} />
      </Routes>
    </div>
  );
}

export default App;
